<?php
namespace App\Console\Commands;
use App\Models\AccountingEvent; use App\Models\Expense; use App\Models\OrderDetail; use App\Models\PurchaseReceiptItem; use App\Models\SalesReturnItem; use Illuminate\Console\Command;
class CoreMarketAccountingEventsAudit extends Command { protected $signature='coremarket:accounting-events-audit'; protected $description='Read-only audit for missing Accounting Lite events'; public function handle(): int { $this->table(['Check','Count'], [['Order details without sale event',OrderDetail::whereDoesntHave('accountingEvents')->count()],['Return items without event',SalesReturnItem::whereDoesntHave('accountingEvents')->count()],['Receipt items without event',PurchaseReceiptItem::whereDoesntHave('accountingEvents')->count()],['Approved expenses without event',Expense::whereIn('status',['approved','paid'])->whereDoesntHave('accountingEvents')->count()],['Sale details without cost snapshot',OrderDetail::whereNull('total_cost')->count()],['Duplicate events',AccountingEvent::selectRaw('reference_type, reference_id, event_type')->groupBy('reference_type','reference_id','event_type')->havingRaw('COUNT(*) > 1')->count()]]); $this->line('No rows were changed.'); return self::SUCCESS; } }
